"""
mkt-christ: Psalms 1-8
Chapters: 1-8 (Ps 2:7 already present; writing 81 missing verses)
Run: python3 scripts/zc-christ-psalms-1-8.py

Key Christ-connection decisions:
- Ps 1: theme — perfect Torah-keeper; Jesus as fulfiller; two-ways eschatology
- Ps 2: direct — Acts 4:25-26 quotes v1-2; Acts 13:33 quotes v7 (already present);
  Rev 2:27; 12:5; 19:15 quote v9; Great Commission grounds v8
- Ps 3: shadow — sleep/waking as death/resurrection type; mockers at cross echo v2
- Ps 4: revelation of God — peace, joy, divine face now seen in Christ (2 Cor 4:6)
- Ps 5: theme + direct — Paul quotes v9 in Rom 3:13 to indict all humanity
- Ps 6: shadow — first penitential psalm; Christ bears the rebuking (Gal 3:13)
- Ps 7: shadow — innocence plea; self-trapping pit; divine warrior absorbing wrath
- Ps 8: direct — Heb 2:6-9 quotes v4-6; 1 Cor 15:27; Eph 1:22; Matt 21:16 quotes v2
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: merge without overwriting any verse already present in existing
    # CHANGE? Do not alter the guard; concurrent agents depend on append-only behavior
    # VERIFY: run twice; second run should report identical byte count for psalms.json
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {"1": {"1": "<p>A theme: the blessed man who refuses the counsel of the wicked, does not stand in the way of sinners, and does not sit in the seat of scoffers describes a life that no fallen human lives perfectly — yet the opening beatitude points toward the one who did. Jesus alone walked through the world without ever taking counsel from the wicked or sitting among scoffers. Where Ps 1 sets the standard, Jesus embodies it: the perfectly Torah-formed human whose delight is unbroken (Matt 5:17: 'I have not come to abolish the Law but to fulfill it').</p>", "2": "<p>A theme: 'his delight is in the law of the LORD, and on his law he meditates day and night' — the portrait of the perfect covenant person who never ceases from Torah-meditation. Jesus is the one who went into the wilderness, enduring each temptation by citing Scripture (Matt 4:1-11); who debated the Pharisees from within the law's depth rather than against it; who declared that not one jot or tittle of the Torah would pass away until all was fulfilled (Matt 5:18). The meditative life of Ps 1 reaches its fulfillment in Christ, who himself is the Word that the Torah mediates.</p>", "3": "<p>A shadow: 'he is like a tree planted by streams of water that yields its fruit in its season.' The tree planted by water as the image of the covenant-loyal person anticipates the NT's vine imagery: Jesus as the true vine (John 15:1-8) who bears fruit and enables others to bear fruit only through abiding connection. The stability of the planted tree — unmoved by drought — foreshadows the one whose root system in the Father's love was unshaken by crucifixion itself.</p>", "4": "<p>A revelation of God: 'the wicked are not so, but are like chaff that the wind drives away' — the instability of all that is not rooted in YHWH. This contrast establishes the eschatological principle that governs the entire Psalter: what is grounded in the covenant endures; what is not is dispersed. The NT develops this as the judgment of the Son of Man who separates wheat from chaff (Matt 3:12; 13:30) — the eschatological harvest Ps 1 announces.</p>", "5": "<p>A theme: 'therefore the wicked will not stand in the judgment, nor sinners in the congregation of the righteous.' The judgment-separation that Ps 1 describes as future reality is what Christ's coming makes both urgent and certain. He is the one appointed to judge the living and the dead (Acts 17:31); the 'standing in the congregation of the righteous' is granted only to those who are clothed in his righteousness (Rom 3:22; Phil 3:9). The psalm's judgment anticipates the criterion: relation to Christ himself.</p>", "6": "<p>A revelation of God: 'for the LORD knows the way of the righteous, but the way of the wicked will perish.' The divine knowing (<i>yodea</i>) — the intimate covenant knowledge — is what secures the righteous. Jesus develops this as the shepherd who 'knows' his sheep (John 10:14-15: 'I know my own and my own know me') and whose knowledge is mutual. Those the Father has given to the Son will not perish (John 10:28-29): the covenant knowing of Ps 1:6 finds its full expression in the Son's reciprocal knowing of the Father and of those who belong to him.</p>"}, "2": {"1": "<p>A direct fulfillment: 'why do the nations rage, and the peoples plot in vain?' Acts 4:25-26 quotes this verse explicitly as fulfilled in the conspiracy against Jesus: the apostles pray, 'Sovereign Lord... you spoke by the Holy Spirit through the mouth of our father David: why did the Gentiles rage, and the peoples plot in vain?' The nations and peoples of Ps 2 are identified as Herod, Pontius Pilate, the Gentiles, and the people of Israel — all gathered against Jesus (Acts 4:27). The rage of the nations is the crucifixion.</p>", "2": "<p>A direct fulfillment: 'the kings of the earth set themselves, and the rulers take counsel together, against the LORD and against his Anointed' — <i>meshicho</i> (his Anointed, his Messiah). The Davidic king of Ps 2 is the Anointed One by title and function; the NT reads this title as referring ultimately to Jesus (Acts 4:26: 'against the Lord and against his Christ'). The coalition that crucified Jesus — Roman power, Herodian client king, Jewish religious leadership — is the fulfillment of the multi-party conspiracy Ps 2 describes.</p>", "3": "<p>A revelation of God: 'let us burst their bonds apart and cast away their cords from us' — the rulers' ambition to free themselves from YHWH's authority. The crucifixion was humanity's definitive attempt to throw off divine governance by killing the divine Son. The claim 'we have no king but Caesar' (John 19:15) is the explicit assertion of this rejection. Yet the attempt to break the cords of covenant becomes the very means by which Christ binds those who trust him (Matt 11:29-30: 'my yoke is easy').</p>", "4": "<p>A revelation of God: 'he who sits in the heavens laughs; the Lord holds them in derision.' The divine laughter at the conspiracy of the powerful is not cruelty but the perception of futility: the plot to overthrow the Creator's Son cannot succeed. The resurrection vindicates the divine laughter — the cross that the conspirators thought final was the precise instrument of their own defeat (1 Cor 2:8: 'if they had understood, they would not have crucified the Lord of glory').</p>", "5": "<p>A revelation of God: 'then he will speak to them in his wrath and terrify them in his fury.' The divine speech in judgment contrasts with the nations' conspiring speech. The final judgment that Ps 2 sets in the future is what Christ's return inaugurates (Rev 19:11-16): the one who was judged by the nations comes as judge. The wrath that Ps 2 announces is what Christ absorbs at the cross (Rom 5:9; 1 Thess 1:10) so that those in him are not subject to it.</p>", "6": "<p>A direct connection: 'as for me, I have set my King on Zion, my holy hill.' The divine installation of the Davidic king on Zion is what the NT interprets as Christ's resurrection and ascension. Acts 2:36 (Peter at Pentecost): 'God has made him both Lord and Christ, this Jesus whom you crucified.' The installation of YHWH's King on the holy hill is not Solomon's coronation but the resurrection enthronement of Jesus at the Father's right hand (Ps 110:1; Acts 2:33-34).</p>", "8": "<p>A direct connection: 'ask of me, and I will make the nations your heritage, and the ends of the earth your possession.' The Father's promise to the Son in Ps 2:8 is what Jesus claims in the Great Commission (Matt 28:18-20: 'All authority in heaven and on earth has been given to me. Go therefore and make disciples of all nations'). The nations as the Son's inheritance is the ground of the universal mission: the Father has already given them; the mission gathers what belongs to the Son.</p>", "9": "<p>A direct connection: 'you shall break them with a rod of iron and dash them in pieces like a potter's vessel.' Rev 2:27, 12:5, and 19:15 all apply this verse to Christ. In Rev 19:15 the rider on the white horse (Christ) 'will rule the nations with a rod of iron.' The iron scepter is both the authority of the enthroned Christ and the instrument of eschatological judgment on all who refuse the Son.</p>", "10": "<p>A theme: 'now therefore, O kings, be wise; be warned, O rulers of the earth.' The summons to the kings anticipates the universal call of the gospel: all rulers, all power-holders, are called to submit to the Son. The 'wisdom' (<i>haskilah</i>) that kings need is the wisdom that acknowledges Christ's lordship — the fear of the Lord that Ps 1:6 and Ps 111:10 describe as wisdom's beginning.</p>", "11": "<p>A theme: 'serve the LORD with fear, and rejoice with trembling.' The paradox of trembling-joy — fear and gladness combined — is the posture that Christ's cross and resurrection create in those who receive him. The NT calls it 'reverent fear' (Phil 2:12: 'work out your salvation with fear and trembling') precisely because the grace that saves is also the holiness that terrifies. The resurrection-joy that comes with acknowledging the Son includes the trembling of those who understand what was at stake.</p>", "12": "<p>A direct connection: 'kiss the Son, lest he be angry, and you perish in the way' — 'blessed are all who take refuge in him.' The 'kiss' as covenant submission and loyalty: in the ANE, kissing the feet of the conquering king was the act of submission. The warning and the beatitude together frame the gospel's structure: the Son is both the one who judges and the one in whom refuge is found. The last word of Ps 2 (<i>ashre</i>, blessed) echoes the first word of Ps 1 (<i>ashre</i>, blessed): the entire framework of the blessed life is defined by relation to the Son.</p>"}, "3": {"1": "<p>A theme: the superscription connects Ps 3 to David fleeing Absalom — a son's rebellion driving out the father. This historical situation becomes a type of the deeper exile Christ entered: the one who came to his own and was not received (John 1:11), who was handed over by those he came to save. The many enemies of Ps 3 who say 'there is no salvation for him in God' (v2) anticipate the mockers at the cross ('He trusts in God; let God deliver him now,' Matt 27:43).</p>", "2": "<p>A theme: 'many are saying of my soul, there is no salvation for him in God.' The mocking of the sufferer's trust in YHWH is the exact taunting at the crucifixion (Matt 27:43: 'He trusts in God; let God deliver him now, if he desires him'). The psalm provides the script that the mockers at Golgotha follow unknowingly — and which the resurrection answers definitively. There was salvation for him in God, precisely because he bore the weight of those who had none.</p>", "3": "<p>A revelation of God: 'but you, O LORD, are a shield about me, my glory, and the lifter of my head.' The divine protection that David confesses in extremity is what Christ claimed in the Garden of Gethsemane: 'Father, if it be possible, let this cup pass from me; nevertheless, not as I will, but as you will' (Matt 26:39). The Father who is the shield of his anointed did not ultimately abandon the Son — the resurrection is the lifting of the head after the crucifixion's shame.</p>", "4": "<p>A revelation of God: 'I cried aloud to the LORD, and he answered me from his holy hill.' The confident prayer answered from Zion — the divine responsiveness to the royal sufferer. The hill of Zion from which YHWH answers anticipates the resurrection-proclamation from Jerusalem: YHWH answered the crucified Son from the 'holy hill' by raising him on the third day (Acts 2:24).</p>", "5": "<p>A shadow: 'I lay down and slept; I woke again, for the LORD sustained me.' The sleep-and-waking of the endangered person becomes a type of death and resurrection when applied to Christ. Jesus quoted similar language of trust in the Father — and slept peacefully in the storm-tossed boat (Mark 4:38) as one who trusted the Father's sustaining power over death itself. The resurrection is the ultimate waking that YHWH's sustaining makes possible.</p>", "6": "<p>A revelation of God: 'I will not be afraid of many thousands of people who have set themselves against me all around.' The fearlessness of the anointed sufferer surrounded by enemies — Christ in Gethsemane, at the arrest, at the trial, on the cross — surrounded by 'many thousands' who sought his destruction, and yet trusting absolutely in the Father's rescue. The steadiness that Ps 3:6 describes is what the Gospel narratives portray as Jesus's unshaken calm before Pilate and on the cross.</p>", "7": "<p>A theme: 'arise, O LORD! Save me, O my God! For you strike all my enemies on the cheek; you break the teeth of the wicked.' The petition for divine arising echoes the resurrection-prayer: 'arise' is the language of YHWH's redemptive action throughout the Psalter and prophets. The striking of enemies on the cheek is ironic when applied to Christ — he was the one struck on the cheek (John 18:22; Matt 5:39: 'if anyone slaps you on the right cheek, turn to him the other also'). The one who absorbed the blow becomes, in resurrection, the one before whom all enemies are struck down.</p>", "8": "<p>A theme: 'salvation belongs to the LORD; your blessing be on your people!' The psalm's closing declaration — salvation (<i>yeshu'ah</i>) is YHWH's possession and gift — is the theological affirmation that the name Jesus embodies (Matt 1:21: 'you shall call his name Jesus, for he will save his people from their sins'). Salvation belongs to YHWH — and YHWH has given it a human name and face in the Son.</p>"}, "4": {"1": "<p>A revelation of God: 'answer me when I call, O God of my righteousness! You have given me relief when I was in distress. Be gracious to me and hear my prayer!' The evening cry to God — the God of the psalmist's righteousness (<i>Elohei tzidqi</i>) — reveals the divine character as the one who gives relief in distress. Christ, the perfectly righteous one, makes this cry his own in Gethsemane and on the cross ('My God, my God, why have you forsaken me?' Ps 22:1) and by entering that distress opens the relief to those who have no righteousness of their own.</p>", "2": "<p>A theme: 'O men, how long shall my honor be turned into shame? How long will you love vain words and seek after lies?' The psalmist's honor turned to shame — the reversal that the righteous experience in a world that honors vanity. Christ's honor was supremely turned to shame at the crucifixion (the purple robe of mockery, the crown of thorns, the placard) — and the resurrection reversed the reversal: 'God has highly exalted him' (Phil 2:9).</p>", "3": "<p>A theme: 'know that the LORD has set apart the godly for himself; the LORD hears when I call to him.' The divine setting-apart of the <i>chasid</i> (godly/loyal one) prefigures Christ's unique setting-apart: the holy one of God whom demons recognized (Mark 1:24), anointed and set apart for the specific mission of bearing the world's sin. The Father's hearing of the Son's prayers (John 11:41-42: 'Father, I thank you that you have heard me') is the covenant assurance of Ps 4:3 realized perfectly.</p>", "4": "<p>A revelation of God: 'be angry, and do not sin; ponder in your own hearts on your beds, and be silent.' Paul quotes this verse in Eph 4:26 as guidance for Christian anger in the community. The revelation here is of a God who acknowledges righteous anger while demanding its discipline — a character fully expressed in Christ who 'drove out those who sold and those who bought' (Mark 11:15) in righteous anger while never sinning. Anger and holiness coexist in Christ as in no other.</p>", "5": "<p>A theme: 'offer right sacrifices, and put your trust in the LORD.' The right sacrifices (<i>zivchei tzedek</i>) — the covenant worship that is both externally correct and internally aligned with trust. Christ both fulfills the sacrificial system (Heb 10:5-10: 'a body you have prepared for me') and abolishes the need for further offering by being himself the right sacrifice. The trust (<i>bitchu</i>) in YHWH is simultaneously the posture Ps 4 calls for and what the sacrifice of Christ enables — access to trust the Father.</p>", "6": "<p>A theme: 'there are many who say, Who will show us some good? Lift up the light of your face upon us, O LORD!' The longing for the face of YHWH to shine — the Aaronic blessing (Num 6:24-26) — is the universal human longing for divine favor. Christ is the answer to this prayer: 'the light of the knowledge of the glory of God in the face of Jesus Christ' (2 Cor 4:6). The divine face the world longed to see became visible in the incarnation.</p>", "7": "<p>A revelation of God: 'you have put more joy in my heart than they have when their grain and wine abound.' The covenant joy that surpasses material prosperity — the joy that Christ imparts is specifically this kind: 'that my joy may be in you, and that your joy may be full' (John 15:11). The abundance of grain and wine (the covenant blessings of earth) yields to the joy of divine presence. The Last Supper itself holds the tension: earthly bread and wine become the sign of the greater covenant joy.</p>", "8": "<p>A theme: 'in peace I will both lie down and sleep; for you alone, O LORD, make me dwell in safety.' The peace that enables sleep — Christ who 'slept' in the boat (Mark 4:38) with absolute peace amid the storm is the model of this trust. The deeper application: the peace that Christ gives is 'not as the world gives' (John 14:27) — it holds even in the face of crucifixion. And his lying down in death became the sleep from which YHWH alone could raise him, making him dwell in ultimate safety.</p>"}, "5": {"1": "<p>A revelation of God: 'give ear to my words, O LORD; consider my groaning.' The morning prayer of the sufferer — the one who cries out at dawn and waits. Christ's prayers in the Gospels are consistently depicted as early and earnest (Mark 1:35: 'rising very early in the morning, while it was still dark, he departed and went to a desolate place, and there he prayed'). The groaning (<i>haggigi</i>) of Ps 5 anticipates the Spirit's groaning in intercession (Rom 8:26) that the Son's work makes possible.</p>", "2": "<p>A revelation of God: 'give attention to the sound of my cry, my King and my God, for to you do I pray.' The address 'my King and my God' — the double royal-divine title — is the posture of covenant prayer. Thomas uses the same double title in his resurrection confession: 'My Lord and my God!' (John 20:28). The prayer of Ps 5:2 addressed to the King and God becomes, in the NT, the worshipful confession addressed to the risen Christ himself.</p>", "3": "<p>A revelation of God: 'O LORD, in the morning you hear my voice; in the morning I prepare a sacrifice for you and watch.' The morning orientation of prayer — the daily sacrifice accompanied by prayer. The morning resurrection: 'early on the first day of the week, while it was still dark' (John 20:1) the women came to the tomb. The morning of the resurrection is the ultimate morning when YHWH heard and answered — the divine hearing of the Son's morning cry vindicated by raising him.</p>", "4": "<p>A revelation of God: 'for you are not a God who delights in wickedness; evil may not dwell with you.' The divine holiness that cannot coexist with evil is the theological background for the atonement. Christ, who 'knew no sin' (2 Cor 5:21), was 'made sin' precisely because the holy God cannot receive sinners as they are. The cross is the event where the divine non-delight in wickedness and the divine love for sinners are simultaneously honored — by transferring the wickedness to the Holy One.</p>", "5": "<p>A revelation of God: 'the boastful shall not stand before your eyes; you hate all evildoers.' The radical divine opposition to evil — 'you hate all evildoers.' This is not incompatible with divine love for sinners: YHWH hates the sin and, in Christ, judges it fully so that the sinner may be freed from it. The cross is where YHWH's hatred of evil and his love for those in evil's grip are both fully expressed — the evil condemned in the flesh (Rom 8:3) so that the person may go free.</p>", "6": "<p>A revelation of God: 'you destroy those who speak lies; the LORD abhors the bloodthirsty and deceitful man.' The divine judgment on the liar and the violent one — what Ps 5:6 announces as YHWH's character becomes, in the NT, the criterion of judgment. The 'blood' language anticipates the blood that speaks better things than Abel's (Heb 12:24) — Christ's blood that speaks not for judgment but for forgiveness.</p>", "7": "<p>A theme: 'but I, through the abundance of your steadfast love, will enter your house.' The ground of access: not merit but <i>chesed</i> (steadfast love). This is the gospel principle before the gospel is announced: the worshiper approaches not on the basis of his own standing but on the basis of YHWH's <i>chesed</i>. Eph 2:8 ('by grace you have been saved through faith') and Heb 10:19-22 (approaching the throne through the blood of Jesus) are the NT fulfillment of this principle.</p>", "8": "<p>A theme: 'lead me, O LORD, in your righteousness because of my enemies; make your way straight before me.' The prayer for divine leading in righteousness — 'your righteousness' (<i>tzidqatecha</i>) — not the worshiper's own. Paul's entire argument in Romans (1:17; 3:21-22) is that the righteousness of God, disclosed in the gospel, is now the ground of the believer's standing: the prayer of Ps 5:8 answered in Christ.</p>", "9": "<p>A direct connection: Paul quotes v9 in Rom 3:13 — 'their throat is an open grave' — as part of the indictment of universal human sinfulness. In Paul's argument, the psalm's description of the wicked is applied to all humanity, Jew and Gentile alike, to show that all stand under condemnation and all need the righteousness of God through faith in Christ (Rom 3:19-22). The wicked man of Ps 5 becomes, in Paul's reading, every man — showing the radical necessity of Christ's righteousness.</p>", "10": "<p>A theme: 'make them bear their guilt, O God; let them fall by their own counsels.' The imprecatory prayer — that the wicked's own schemes return on their heads. The cross is the supreme instance of this irony: those who plotted against the Son of God ensured through their plotting the very salvation they were trying to prevent. The 'counsels' that destroyed Jesus were the precise instrument by which YHWH defeated sin and death (Acts 2:23: 'this Jesus, delivered up according to the definite plan and foreknowledge of God').</p>", "11": "<p>A theme: 'but let all who take refuge in you rejoice; let them ever sing for joy, and spread your protection over them, that those who love your name may exult in you.' The joy of those who take refuge in YHWH — this is the community of Christ: those who have taken refuge specifically in the Son, in whom all the promises of YHWH are 'Yes and Amen' (2 Cor 1:20). The name they love is now embodied in Jesus: 'the name that is above every name' (Phil 2:9).</p>", "12": "<p>A theme: 'for you bless the righteous, O LORD; you cover him with favor as with a shield.' The divine blessing and covering of the righteous — the righteousness that qualifies for blessing is now 'not my own righteousness, which comes from the law, but that which comes through faith in Christ, the righteousness from God that depends on faith' (Phil 3:9). The shield of favor that Ps 5 promises is extended to those who are 'in Christ' — the righteous one who covers them with his own standing.</p>"}, "6": {"1": "<p>A shadow: Ps 6 is the first of the seven penitential psalms (6, 32, 38, 51, 102, 130, 143). It opens with the cry not to be rebuked in divine anger — the fear of divine wrath that the covenant people rightly felt under the law's condemnation. Christ absorbs this rebuking: 'Christ redeemed us from the curse of the law by becoming a curse for us' (Gal 3:13). The rebuking anger that Ps 6 fears is the anger Christ bore, so that those who trust him receive instead the blessing.</p>", "2": "<p>A shadow: 'be gracious to me, O LORD, for I am languishing; heal me, O LORD, for my bones are troubled.' The embodied suffering of the penitent — bones troubled, soul terrified. Christ entered this embodied vulnerability fully: in Gethsemane, 'his sweat became like great drops of blood falling down to the ground' (Luke 22:44); on the cross, the Johannine account notes that not a bone was broken (John 19:36, fulfilling Ps 34:20) — yet he bore the full spiritual anguish of the troubled soul.</p>", "3": "<p>A shadow: 'my soul also is greatly troubled. But you, O LORD — how long?' The 'how long?' of the penitent's cry — the central question of lament. At Golgotha, 'My God, my God, why have you forsaken me?' (Ps 22:1) is the ultimate 'how long?' The silence of God that the penitent experiences is what Christ entered to its absolute depth, so that the believer who prays 'how long?' does so as one who knows that YHWH has already answered in the resurrection.</p>", "4": "<p>A shadow: 'turn, O LORD, deliver my soul; save me for the sake of your steadfast love.' The petition grounded in <i>chesed</i> — save not because of my merit but because of your covenant love. This is the ground of all atonement: YHWH saves 'for the sake of your steadfast love' (<i>lema'an chasdecha</i>). Christ's atoning work is itself the supreme expression of divine <i>chesed</i> (John 3:16: 'for God so loved the world that he gave...') — the covenant-love given its fullest form in the cross.</p>", "5": "<p>A shadow: 'for in death there is no remembrance of you; in Sheol who will give you praise?' The OT concern that death silences praise. Christ's descent into death (1 Pet 3:18-19; Eph 4:9) and his resurrection out of it is the answer to this fear: he went where praise was impossible and returned, making the resurrection the foundation of eternal praise. Heb 2:12 quotes Ps 22:22 ('I will tell of your name to my brothers; in the midst of the congregation I will sing your praise') as what the risen Christ does — praise has been restored from the dead.</p>", "6": "<p>A shadow: 'I am weary with my moaning; every night I flood my bed with tears; I drench my couch with my weeping.' The depths of the penitent's grief — the physical expression of spiritual distress. Jesus wept (John 11:35) — the Son of God entering the full range of human grief. Heb 5:7 describes Jesus in Gethsemane: 'he offered up prayers and supplications, with loud cries and tears, to him who was able to save him from death.' The weeping of Ps 6 finds its fullest expression and its final answer in Christ's tears and resurrection.</p>", "7": "<p>A shadow: 'my eye wastes away because of grief; it grows weak because of all my foes.' The physical dimming through grief — the body bearing the weight of spiritual distress. The 'foes' who cause this grief are, in Christ's case, the systemic powers of sin, death, and the devil that he entered combat with. His 'weakness' at the cross (2 Cor 13:4: 'he was crucified in weakness') is the entry point for divine power: 'he was raised by the power of God.'</p>", "8": "<p>A theme: 'depart from me, all you workers of evil, for the LORD has heard the sound of my weeping.' The confident reversal — the psalmist's assurance that YHWH has heard. Jesus uses the language of this verse ('depart from me') in Matt 7:23, addressed to those who called him Lord but did not know him, and in Matt 25:41, addressed to those who failed to serve him in the poor. The 'depart from me' of Ps 6:8 becomes the eschatological judgment-word of the Son.</p>", "9": "<p>A theme: 'the LORD has heard my plea; the LORD accepts my prayer.' The confident assurance of answered prayer — what the penitent gains from entering the suffering of Ps 6. Christ's prayers were always heard by the Father (John 11:42). And through Christ, the prayers of those who come to God 'through him' are accepted (Heb 7:25: 'he is able to save to the uttermost those who draw near to God through him, since he always lives to make intercession for them').</p>", "10": "<p>A theme: 'all my enemies shall be ashamed and greatly troubled; they shall turn back and be put to shame in a moment.' The final reversal — the shame that the penitent feared (v1: fear of divine rebuke) is redirected to the enemies. The resurrection is the moment when the shame is redirected: those who killed the Son are confronted with the one they crucified (Acts 2:36: 'let all the house of Israel therefore know for certain that God has made him both Lord and Christ, this Jesus whom you crucified'). The 'in a moment' of the reversal anticipates the sudden transformation of the third day.</p>"}, "7": {"1": "<p>A shadow: 'O LORD my God, in you do I take refuge; save me from all my pursuers and deliver me.' The fugitive's cry for divine protection. The superscription connects to Cush the Benjaminite — a false accusation episode in David's life. As a shadow: Jesus alone was pursued by accusers whose charges were entirely false (Matt 26:59-60: 'the chief priests and the whole council were seeking false testimony against Jesus'). The innocent fugitive who takes refuge in YHWH is the template Christ inhabits at his trial.</p>", "2": "<p>A shadow: 'lest like a lion they tear my soul apart, rending it in pieces, with none to deliver.' The lion tearing as the image of enemy destruction. Peter uses the same image for the devil: 'your adversary the devil prowls around like a roaring lion, seeking someone to devour' (1 Pet 5:8). At the cross, the lion was unleashed — and the one torn was Christ, so that those who take refuge in him are not devoured.</p>", "3": "<p>A shadow: 'O LORD my God, if I have done this, if there is wrong in my hands' — the protestation of innocence. Jesus alone could make this claim before YHWH with absolute truthfulness. Pilate's declaration 'I find no guilt in him' (John 18:38) is the judicial echo of the psalmist's claim. The one who bore the world's guilt was the one who had committed none of his own — the substitution requires this precise innocence.</p>", "4": "<p>A shadow: 'if I have repaid my friend with evil or plundered my enemy without cause...' — the negative covenant oath. Christ's covenant faithfulness was total: he never repaid evil with evil (1 Pet 2:23: 'when he was reviled, he did not revile in return') and never plundered unjustly. The perfection of his human covenant-keeping is what makes him the acceptable substitute for those who have broken every covenant term.</p>", "5": "<p>A shadow: 'let the enemy pursue my soul and overtake it, and let him trample my life to the ground and lay my glory in the dust.' The ultimate curse-formula — what the psalmist says should happen if he is guilty. Christ voluntarily entered this curse for those who were guilty: 'he made him to be sin who knew no sin' (2 Cor 5:21). The glory laid in the dust is the incarnation and crucifixion; the resurrection is the divine vindication that proves the guilt was transferred, not inherent.</p>", "6": "<p>A revelation of God: 'arise, O LORD, in your anger; lift yourself up against the fury of my enemies; awake for me; you have appointed a judgment.' The petition for divine arising to judge — the 'arise, O LORD' cry echoes the Sinai prayer (Num 10:35). The divine judgment that Ps 7 calls for is what Christ's return inaugurates: the appointed judge (Acts 17:31) rises to render the verdict that history has been waiting for.</p>", "7": "<p>A revelation of God: 'let the assembly of the peoples be gathered about you; over it return on high.' The universal assembly gathered around YHWH — the eschatological vision: all peoples assembled before the divine throne. Rev 20:11-12 depicts this: 'a great white throne and him who was seated on it... and I saw the dead, great and small, standing before the throne.' The Judge of Ps 7 is the Christ of Rev 20.</p>", "8": "<p>A theme: 'the LORD judges the peoples; judge me, O LORD, according to my righteousness and according to the integrity that is in me.' The appeal to divine justice — which is also the appeal to divine mercy for those who have no righteousness of their own. Paul's argument in Romans is precisely that no one can say 'judge me according to my righteousness' — except the one who has Christ's righteousness imputed to them. The prayer of Ps 7:8 becomes safe only for those in whom Christ's integrity stands.</p>", "9": "<p>A revelation of God: 'oh, let the evil of the wicked come to an end, and may you establish the righteous — you who test minds and hearts, O righteous God!' The searching of minds and hearts by the righteous God — the divine omniscience applied to moral judgment. 'The heart is deceitful above all things... who can understand it? I the LORD search the heart and test the mind' (Jer 17:9-10). Jesus, who 'knew what was in man' (John 2:25), exercises this divine prerogative as the Son who knows the Father.</p>", "10": "<p>A theme: 'my shield is with God, who saves the upright in heart.' The divine shield again (cf. Gen 15:1; Ps 3:3) — YHWH as protector of the upright. Christ is both the shield and the one who makes the upright: 'the upright in heart' are those whose hearts have been transformed by the Spirit (Ezek 36:26; Ps 51:10) so that they may stand in the judgment Ps 7 describes.</p>", "11": "<p>A revelation of God: 'God is a righteous judge, and a God who feels indignation every day.' The perpetual divine indignation at injustice — YHWH does not grow accustomed to sin. This perpetual moral attentiveness is what makes the atonement necessary: every sin is registered by the one who 'feels indignation every day.' The cross is where this daily indignation is absorbed in full, so that those in Christ stand before the righteous judge without condemnation (Rom 8:1).</p>", "12": "<p>A revelation of God: 'if a man does not repent, God will whet his sword; he has bent and readied his bow.' The divine warning: the sword and bow of divine judgment are prepared for the unrepentant. The urgency of repentance — what the NT calls 'today' (Heb 3:7,13,15: 'today, if you hear his voice, do not harden your hearts') is the urgency of Ps 7:12. The prepared sword is not yet swung; the repentance that turns it is available now through Christ.</p>", "13": "<p>A revelation of God: 'he has prepared for him his deadly weapons, making his arrows fiery shafts.' The divine warrior's arsenal — the weapons of the holy war are prepared specifically for the unrepentant. Yet Christ takes the fire: 'Christ redeemed us from the curse of the law by becoming a curse for us' (Gal 3:13) — the fiery shaft of divine judgment struck the Son so that it need not strike those who take refuge in him.</p>", "14": "<p>A theme: 'behold, the wicked man conceives evil and is pregnant with mischief and gives birth to lies.' The wicked person's internal trajectory — evil conceived, born as mischief, delivered as lies. James 1:15 describes sin's similar trajectory: 'desire when it has conceived gives birth to sin, and sin when it is fully grown brings forth death.' Christ enters the world precisely where this trajectory has led: a world full of the death that sin-conceived-in-mischief produces.</p>", "15": "<p>A shadow: 'he makes a pit, digging it out, and falls into the hole he has made.' The self-trapping principle of evil — the pit-digger falls into his own pit (Prov 26:27; Eccl 10:8). Applied to the crucifixion: those who plotted to destroy Jesus through death were unwittingly using the instrument of their own defeat. The resurrection is the moment when the enemy falls into the pit: death is defeated by death (Heb 2:14: 'through death he might destroy the one who has the power of death, that is, the devil').</p>", "16": "<p>A shadow: 'his mischief returns upon his own head, and on his own skull his violence descends.' The law of return: violence against the innocent returns on the violent. The cross applies this: YHWH allowed the violence of crucifixion to fall on the innocent Son — and it returned on all who hold the power of sin and death through the resurrection. Satan's greatest weapon (death) became his own defeat.</p>", "17": "<p>A revelation of God: 'I will give to the LORD the thanks due to his righteousness, and I will sing praise to the name of the LORD, the Most High.' The psalm ends in doxology — as most penitential-vindication psalms do. The pattern (crisis → lament → confidence → praise) is the structure of the gospel itself: the crisis of human sin → the lament of the cross → the confidence of the resurrection → the eternal praise of those who are vindicated in Christ. The 'name of the LORD, the Most High' is the name now borne by Jesus: 'the name that is above every name' (Phil 2:9).</p>"}, "8": {"1": "<p>A direct connection: 'O LORD, our Lord, how majestic is your name in all the earth! You have set your glory above the heavens.' Ps 8 is the psalm the NT most explicitly applies to Christ. The majestic name 'in all the earth' anticipates the name 'above every name' (Phil 2:9-10). The glory set above the heavens is what the Son shared with the Father before the world existed (John 17:5: 'Father, glorify me in your own presence with the glory that I had with you before the world existed') and what the incarnation temporarily veiled.</p>", "2": "<p>A direct connection: Jesus quotes this verse in Matt 21:16 in response to the Pharisees' objection to the children crying 'Hosanna!' in the temple. 'Have you never read, Out of the mouth of infants and nursing babies you have prepared praise?' The children's Hosannas in the temple are the fulfillment of Ps 8:2 — the praise of the weak silences the enemy. Christ's claim that the children's praise fulfills Ps 8 means he identifies himself as the one whose name elicits this praise.</p>", "3": "<p>A revelation of God: 'when I look at your heavens, the work of your fingers, the moon and the stars, which you have set in place' — the created order as the work of divine fingers. The creator who set the stars in place (Ps 147:4: 'he determines the number of the stars; he gives to all of them their names') became flesh in the incarnation. John 1:3: 'all things were made through him, and without him was not any thing made that was made.' The creator entered his creation as the creature the next verses describe.</p>", "4": "<p>A direct connection: Heb 2:6-9 quotes this verse as applying to Christ: 'it has been testified somewhere, What is man, that you are mindful of him, or the son of man, that you care for him?' The 'son of man' (<i>ben adam</i>) of Ps 8:4 is applied in Hebrews to Jesus, who 'for a little while was made lower than the angels' (= the incarnation and humiliation of Ps 8:5a), then 'crowned with glory and honor because of the suffering of death' (= the resurrection and exaltation of Ps 8:5b). Ps 8:4 is the question the incarnation answers.</p>", "5": "<p>A direct connection: Heb 2:7,9 applies both halves of this verse to Christ. 'You made him for a little while lower than the angels' = the incarnation, in which the Son who is 'far superior to angels' (Heb 1:4) nevertheless 'was made lower than the angels' through taking on flesh and mortality. 'You have crowned him with glory and honor' = the resurrection and ascension: 'we see him who for a little while was made lower than the angels, namely Jesus, crowned with glory and honor because of the suffering of death' (Heb 2:9).</p>", "6": "<p>A direct connection: Paul quotes 'you have put all things under his feet' in 1 Cor 15:27 and the same language appears in Eph 1:22 ('he put all things under his feet and gave him as head over all things to the church') and Heb 2:8 ('leaving nothing outside his control'). The subjection of 'all things' under the son of man is fully realized in Christ's resurrection and reign. 1 Cor 15:24-28 clarifies: the subjection is not yet fully visible — Christ reigns now and will reign until all enemies including death itself are put under his feet.</p>", "7": "<p>A theme: 'all sheep and oxen, and also the beasts of the field' — the animals under human (and thus Christ's) dominion. The dominion mandate of Gen 1:28 ('have dominion over the fish of the sea and over the birds of the heavens and over every living thing') is what Ps 8 celebrates and what Christ's resurrection-kingship restores. The groaning creation (Rom 8:19-22) awaits the full revelation of the children of God — when the dominion of Ps 8 is restored through the one who became the son of man to reclaim it.</p>", "8": "<p>A theme: 'the birds of the heavens, and the fish of the sea, whatever passes along the paths of the seas.' The completeness of the creation-dominion — birds, fish, sea-paths. Christ's mastery over creation anticipates the restored dominion: he commands fish (Luke 5:4-7; John 21:6), calms seas (Mark 4:39), walks on water (Matt 14:25). These are not magic tricks but demonstrations that the son of man of Ps 8 has come — the one in whom the creation-dominion of Adam is restored and surpassed.</p>", "9": "<p>A direct connection: 'O LORD, our Lord, how majestic is your name in all the earth!' The psalm closes as it opened — with the majestic name. In the NT's reading of Ps 8, this final doxology is also the first: the name that is majestic 'in all the earth' is the name of Jesus, before whom 'every knee should bow, in heaven and on earth and under the earth, and every tongue confess that Jesus Christ is Lord, to the glory of God the Father' (Phil 2:10-11). The earthly majestic name of Ps 8 becomes the cosmic-universal name of the crucified and risen Son.</p>"}}

if __name__ == '__main__':
    book = 'psalms'
    source = 'mkt-christ'
    existing = load_comm(source, book)
    merge_comm(existing, NEW_DATA)
    save_comm(source, book, existing)
    for ch, vv in NEW_DATA.items():
        saved = existing.get(ch, {})
        missing = [v for v in vv if v not in saved]
        print(f'  ch {ch}: {len(vv)} entries, {len(missing)} missing after merge')
